  8→};
  9→
 10→export type ServerConfig = {
 11→  openRouterApiKey: string;
 12→  chatAgentModelId: string;
 13→  extractionModelId: string;
 14→  pmAgentModelId: string;
 15→  analyticsAgentModelId: string;
 16→  embeddingModelId: string;
 17→  embeddingDimension: number;
 18→  extractionStoreThreshold: number;
 19→  extractionDisplayThreshold: number;
 20→  openRouterReasoning?: OpenRouterReasoningOptions;
 21→  surrealUrl: string;
 22→  surrealUsername: string;
 23→  surrealPassword: string;
 24→  surrealNamespace: string;
 25→  surrealDatabase: string;
 26→  port: number;
 27→  githubWebhookSecret?: string;
 28→};
 29→
 30→export function loadServerConfig(): ServerConfig {
 31→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 32→
 33→  const extractionStoreThreshold = parseUnitInterval(
 34→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 35→    "EXTRACTION_STORE_THRESHOLD",
 36→  );
 37→
 38→  const extractionDisplayThreshold = parseUnitInterval(
 39→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 40→    "EXTRACTION_DISPLAY_THRESHOLD",
 41→  );
 42→
 43→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 44→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 45→  }
 46→
 47→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 48→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 49→  const pmAgentModelId = Bun.env.PM_AGENT_MODEL && Bun.env.PM_AGENT_MODEL.trim().length > 0
 50→    ? Bun.env.PM_AGENT_MODEL.trim()
 51→    : extractionModelId;
 52→  const analyticsAgentModelId = requireEnv("ANALYTICS_MODEL");
 53→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 54→  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");
 55→
 56→  const surrealUrl = requireEnv("SURREAL_URL");
 57→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 58→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 59→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 60→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 61→
 62→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 63→  const githubWebhookSecret = Bun.env.GITHUB_WEBHOOK_SECRET?.trim() || undefined;
 64→
 65→  return {
 66→    openRouterApiKey,
 67→    chatAgentModelId,
 68→    extractionModelId,
 69→    pmAgentModelId,
 70→    analyticsAgentModelId,
 71→    embeddingModelId,
 72→    embeddingDimension,
 73→    extractionStoreThreshold,
 74→    extractionDisplayThreshold,
 75→    openRouterReasoning: parseOpenRouterReasoning(),
 76→    surrealUrl,
 77→    surrealUsername,
 78→    surrealPassword,
 79→    surrealNamespace,
 80→    surrealDatabase,
 81→    port,
 82→    ...(githubWebhookSecret ? { githubWebhookSecret } : {}),
 83→  };
 84→}
 85→
 86→function requireEnv(name: string): string {
 87→  const value = Bun.env[name];
 88→  if (!value || value.trim().length === 0) {
 89→    throw new Error(`${name} is required`);
 90→  }
 91→
 92→  return value;
 93→}
 94→
 95→function parsePositiveInteger(value: string, envName: string): number {
 96→  const parsed = Number(value);
 97→  if (!Number.isInteger(parsed) || parsed < 1) {
 98→    throw new Error(`${envName} must be a positive integer`);
 99→  }
100→  return parsed;
101→}
102→
103→function parseUnitInterval(value: string, envName: string): number {
104→  const parsed = Number(value);
105→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
106→    throw new Error(`${envName} must be a number between 0 and 1`);
107→  }
108→
109→  return parsed;
110→}
111→
112→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
113→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
114→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
115→
116→  if (!effortValue && !maxTokensValue) {
117→    return undefined;
118→  }
119→
120→  const reasoning: OpenRouterReasoningOptions = {};
121→
122→  if (effortValue) {
123→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
124→
125→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
126→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
127→    }
128→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
129→  }
130→
131→  if (maxTokensValue) {
132→    const parsed = Number(maxTokensValue);
133→    if (!Number.isFinite(parsed) || parsed < 1) {
134→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
135→    }
136→    reasoning.max_tokens = parsed;
137→  }
138→
139→  return reasoning;
140→}
