 1→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
 2→import { Surreal } from "surrealdb";
 3→import type { ServerConfig } from "./config";
 4→
 5→export async function createRuntimeDependencies(config: ServerConfig): Promise<{
 6→  surreal: Surreal;
 7→  analyticsSurreal: Surreal;
 8→  chatAgentModel: any;
 9→  extractionModel: any;
10→  pmAgentModel: any;
11→  analyticsAgentModel: any;
12→  embeddingModel: any;
13→}> {
14→  const surreal = new Surreal();
15→  await surreal.connect(config.surrealUrl);
16→  await surreal.signin({ username: config.surrealUsername, password: config.surrealPassword });
17→  await surreal.use({ namespace: config.surrealNamespace, database: config.surrealDatabase });
18→
19→  const analyticsSurreal = new Surreal();
20→  await analyticsSurreal.connect(config.surrealUrl);
21→  await analyticsSurreal.signin({
22→    namespace: config.surrealNamespace,
23→    database: config.surrealDatabase,
24→    username: "analytics",
25→    password: "brain-analytics-readonly",
26→  });
27→  await analyticsSurreal.use({ namespace: config.surrealNamespace, database: config.surrealDatabase });
28→
29→  const openrouter = createOpenRouter({ apiKey: config.openRouterApiKey });
30→  const chatAgentModel = openrouter(config.chatAgentModelId, {
31→    plugins: [{ id: "response-healing" }],
32→    ...(config.openRouterReasoning ? { extraBody: { reasoning: config.openRouterReasoning } } : {}),
33→  });
34→  const extractionModel = openrouter(config.extractionModelId, {
35→    plugins: [{ id: "response-healing" }],
36→    ...(config.openRouterReasoning ? { extraBody: { reasoning: config.openRouterReasoning } } : {}),
37→  });
38→  const pmAgentModel = openrouter(config.pmAgentModelId, {
39→    plugins: [{ id: "response-healing" }],
40→    ...(config.openRouterReasoning ? { extraBody: { reasoning: config.openRouterReasoning } } : {}),
41→  });
42→  const analyticsAgentModel = openrouter(config.analyticsAgentModelId, {
43→    plugins: [{ id: "response-healing" }],
44→  });
45→  const embeddingModel = openrouter.textEmbeddingModel(config.embeddingModelId);
46→
47→  return {
48→    surreal,
49→    analyticsSurreal,
50→    chatAgentModel,
51→    extractionModel,
52→    pmAgentModel,
53→    analyticsAgentModel,
54→    embeddingModel,
55→  };
56→}
