357→DEFINE FUNCTION fn::entity_search_workspace($vec: array<float>, $limit: int, $workspace: record<workspace>) {
358→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
359→
360→  LET $task_rows = SELECT
361→    id, "task" AS kind, title AS text,
362→    vector::similarity::cosine(embedding, $vec) AS similarity
363→  FROM task
364→  WHERE workspace = $workspace AND embedding <|20, COSINE|> $vec
365→  ORDER BY similarity DESC LIMIT $safe_limit;
366→
367→  LET $decision_rows = SELECT
368→    id, "decision" AS kind, summary AS text,
369→    vector::similarity::cosine(embedding, $vec) AS similarity
370→  FROM decision
371→  WHERE workspace = $workspace AND embedding <|20, COSINE|> $vec
372→  ORDER BY similarity DESC LIMIT $safe_limit;
373→
374→  LET $question_rows = SELECT
375→    id, "question" AS kind, text AS text,
376→    vector::similarity::cosine(embedding, $vec) AS similarity
377→  FROM question
378→  WHERE workspace = $workspace AND embedding <|20, COSINE|> $vec
379→  ORDER BY similarity DESC LIMIT $safe_limit;
380→
381→  LET $observation_rows = SELECT
382→    id, "observation" AS kind, text AS text,
383→    vector::similarity::cosine(embedding, $vec) AS similarity
384→  FROM observation
385→  WHERE workspace = $workspace AND embedding <|20, COSINE|> $vec
386→  ORDER BY similarity DESC LIMIT $safe_limit;
387→
388→  LET $feature_rows = SELECT
389→    id, "feature" AS kind, name AS text,
390→    vector::similarity::cosine(embedding, $vec) AS similarity
391→  FROM feature
392→  WHERE embedding <|20, COSINE|> $vec
393→  ORDER BY similarity DESC LIMIT $safe_limit;
394→
395→  LET $project_rows = SELECT
396→    id, "project" AS kind, name AS text,
397→    vector::similarity::cosine(embedding, $vec) AS similarity
398→  FROM project
399→  WHERE workspace = $workspace AND embedding <|20, COSINE|> $vec
400→  ORDER BY similarity DESC LIMIT $safe_limit;
401→
402→  LET $person_rows = SELECT
403→    id, "person" AS kind, name AS text,
404→    vector::similarity::cosine(embedding, $vec) AS similarity
405→  FROM person
406→  WHERE embedding <|20, COSINE|> $vec
407→  ORDER BY similarity DESC LIMIT $safe_limit;
408→
409→  LET $message_rows = SELECT
410→    id, "message" AS kind, text AS text,
411→    vector::similarity::cosine(embedding, $vec) AS similarity
412→  FROM message
413→  WHERE conversation.workspace = $workspace AND embedding <|20, COSINE|> $vec
414→  ORDER BY similarity DESC LIMIT $safe_limit;
415→
416→  LET $all = array::flatten([$task_rows, $decision_rows, $question_rows, $observation_rows, $feature_rows, $project_rows, $person_rows, $message_rows]);
417→  RETURN SELECT * FROM $all ORDER BY similarity DESC LIMIT $safe_limit;
418→};
