 44→export function createWorkspaceRouteHandlers(deps: ServerDependencies): {
 45→  handleCreateWorkspace: (request: Request) => Promise<Response>;
 46→  handleWorkspaceBootstrap: (workspaceId: string) => Promise<Response>;
 47→  handleWorkspaceSidebar: (workspaceId: string) => Promise<Response>;
 48→  handleWorkspaceConversation: (workspaceId: string, conversationId: string) => Promise<Response>;
 49→} {
 50→  return {
 51→    handleCreateWorkspace: (request: Request) => handleCreateWorkspace(deps, request),
 52→    handleWorkspaceBootstrap: (workspaceId: string) => handleWorkspaceBootstrap(deps, workspaceId),
 53→    handleWorkspaceSidebar: (workspaceId: string) => handleWorkspaceSidebar(deps, workspaceId),
